using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = [];

    public CatalogService()
    {
        _departments =
        [
            new() { Id = 1, Code = "CS",   Name = "Computer Science",       Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics",            Description = "Exploration of abstract structures, quantities, and patterns." },
            new() { Id = 3, Code = "PHYS", Name = "Physics",                Description = "Understanding the fundamental laws governing the natural world." },
            new() { Id = 4, Code = "ENG",  Name = "English",                Description = "Literature, writing, and critical analysis of texts." },
            new() { Id = 5, Code = "HIST", Name = "History",                Description = "Examination of past events and their impact on the present." },
            new() { Id = 6, Code = "BIO",  Name = "Biology",                Description = "Study of living organisms, their structure, and processes." },
        ];

        _instructors =
        [
            new() { Id = 1, Name = "Dr. Alice Chen",      Title = "Professor",           Email = "achen@university.edu",     Bio = "Dr. Chen has over 15 years of experience in software engineering and distributed systems. She has published extensively on cloud-native architectures and holds a Ph.D. from MIT.",                         OfficeHours = "Mon/Wed 2:00–4:00 PM" },
            new() { Id = 2, Name = "Dr. Robert Martinez",  Title = "Associate Professor", Email = "rmartinez@university.edu", Bio = "Dr. Martinez specializes in abstract algebra and number theory. He is the recipient of the National Mathematics Teaching Award and has authored two widely-used textbooks.",                        OfficeHours = "Tue/Thu 10:00 AM–12:00 PM" },
            new() { Id = 3, Name = "Dr. Sarah Okafor",     Title = "Professor",           Email = "sokafor@university.edu",   Bio = "Dr. Okafor is a leading researcher in quantum mechanics with contributions to superconductor theory. She previously worked at CERN and holds multiple international physics awards.",                  OfficeHours = "Mon/Fri 1:00–3:00 PM" },
            new() { Id = 4, Name = "Prof. James Liu",      Title = "Senior Lecturer",     Email = "jliu@university.edu",      Bio = "Prof. Liu is an acclaimed novelist and literary critic. His courses emphasize creative expression, diverse voices in literature, and the craft of storytelling.",                                       OfficeHours = "Wed 9:00–11:00 AM" },
            new() { Id = 5, Name = "Dr. Maria Gonzalez",   Title = "Associate Professor", Email = "mgonzalez@university.edu", Bio = "Dr. Gonzalez is a historian of early modern Europe with a focus on the Atlantic world. She has received fellowships from the NEH and the Fulbright Program.",                                     OfficeHours = "Tue/Thu 3:00–5:00 PM" },
            new() { Id = 6, Name = "Dr. David Park",       Title = "Assistant Professor",  Email = "dpark@university.edu",     Bio = "Dr. Park researches molecular genetics and CRISPR technologies. He completed postdoctoral work at the NIH and has published in Nature and Cell.",                                                   OfficeHours = "Mon/Wed 10:00 AM–12:00 PM" },
            new() { Id = 7, Name = "Dr. Emily Watson",     Title = "Professor",           Email = "ewatson@university.edu",   Bio = "Dr. Watson specializes in artificial intelligence and machine learning. She co-founded an AI research lab and has over 50 publications in top-tier conferences.",                                    OfficeHours = "Tue/Thu 1:00–3:00 PM" },
            new() { Id = 8, Name = "Dr. Thomas Reed",      Title = "Senior Lecturer",     Email = "treed@university.edu",     Bio = "Dr. Reed brings 20 years of industry experience in statistical modeling and data science. He previously led analytics teams at two Fortune 500 companies.",                                        OfficeHours = "Mon/Wed 3:00–5:00 PM" },
        ];

        _courses =
        [
            new() { Id = 1,  Code = "CS 101",   Title = "Introduction to Computer Science",  Description = "An introductory course covering fundamental concepts of programming, data structures, and algorithmic thinking. Students will learn Python and build small projects.",                                     Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM",   Room = "Science Hall 201",   DepartmentId = 1, DepartmentName = "Computer Science",  Instructor = _instructors[0], IsFeatured = true,  MaxEnrollment = 120, CurrentEnrollment = 98  },
            new() { Id = 2,  Code = "CS 301",   Title = "Data Structures and Algorithms",    Description = "Advanced study of data structures (trees, graphs, hash tables) and algorithm design (divide-and-conquer, dynamic programming, greedy algorithms). Prerequisite: CS 101.",                                 Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM",      Room = "Science Hall 305",   DepartmentId = 1, DepartmentName = "Computer Science",  Instructor = _instructors[0], IsFeatured = false, MaxEnrollment = 60,  CurrentEnrollment = 55  },
