arguments.file_text:
@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Home — University Course Catalog</PageTitle>

<h1>Welcome to the University Course Catalog</h1>
<p class="lead">Browse our Fall 2026 course offerings, explore departments, and submit your enrollment request.</p>

<hr />

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in Catalog.GetFeaturedCourses())
    {
        <div class="col-md-6 col-lg-4 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.Code — @course.Title</h5>
                    <p class="card-text text-muted">@course.Credits credits · @course.DepartmentName</p>
                    <p class="card-text">@Truncate(course.Description, 120)</p>
                </div>
                <div class="card-footer bg-transparent">
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                    <a href="enroll?courseId=@course.Id" class="btn btn-outline-success btn-sm">Enroll</a>
                </div>
            </div>
        </div>
    }
</div>

<hr />

<h2>Departments</h2>
<div class="row">
    @foreach (var dept in Catalog.GetDepartments())
    {
        <div class="col-md-4 col-lg-3 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text text-muted">@dept.Code</p>
                    <a href="departments/@dept.Id" class="btn btn-outline-primary btn-sm">Browse Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private static string Truncate(string text, int maxLength)
    {
        if (text.Length <= maxLength) return text;
        return string.Concat(text.AsSpan(0, maxLength), "…");
    }
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Courses — University Course Catalog</PageTitle>

<h1>Course Catalog</h1>
<p>Search and filter courses across all departments.</p>

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search by title, code, description, or instructor…" />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in Catalog.GetDepartments())
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Search</button>
    </div>
</form>

@{
    var results = Catalog.SearchCourses(Search, DepartmentId);
}

<p class="text-muted">Showing @results.Count course(s)</p>

<div class="table-responsive">
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th>Schedule</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in results)
            {
                <tr>
                    <td><strong>@course.Code</strong></td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.Instructor.Name</td>
                    <td>@course.Schedule</td>
                    <td>
                        <a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a>
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@if (results.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria. Try broadening your search.</div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

@{
    var course = Catalog.GetCourse(Id);
}

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The course you are looking for does not exist.</p>
    <a href="courses" class="btn btn-primary">Back to Courses</a>
}
else
{
    <PageTitle>@course.Code — @course.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item"><a href="departments/@course.DepartmentId">@course.DepartmentName</a></li>
            <li class="breadcrumb-item active">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            <h4 class="mt-4">Schedule &amp; Location</h4>
            <table class="table table-sm" style="max-width: 400px;">
                <tr><th>Schedule</th><td>@course.Schedule</td></tr>
                <tr><th>Room</th><td>@course.Room</td></tr>
                <tr><th>Credits</th><td>@course.Credits</td></tr>
            </table>

